//! Quick performance check for stats-rs vs CLAUDE.md targets
use stats_models::Lm;
use std::time::Instant;

fn main() {
    println!("=== RUST STATS PERFORMANCE BENCHMARK ===");

    // Test different sizes
    let test_cases = vec![
        (50, 3, "Small"),
        (100, 5, "Medium"),
        (500, 10, "Large"),
        (1000, 10, "Extra Large"),
    ];

    for (n_obs, n_vars, name) in test_cases {
        println!(
            "\n{} dataset: {} observations, {} variables",
            name, n_obs, n_vars
        );

        // Generate test data
        let mut x_data = Vec::with_capacity(n_obs * n_vars);
        let mut y_data = Vec::with_capacity(n_obs);

        for i in 0..n_obs {
            x_data.push(1.0); // intercept
            for j in 1..n_vars {
                x_data.push((i as f64 + j as f64) * 0.1);
            }
            let y = 1.0
                + (0..n_vars - 1)
                    .map(|j| (i as f64 + j as f64) * 0.1 * 0.5)
                    .sum::<f64>();
            y_data.push(y);
        }

        // Warm up
        for _ in 0..10 {
            let _ = Lm::fit(&x_data, &y_data, n_obs, n_vars).unwrap();
        }

        // Time multiple runs
        let runs = 100;
        let start = Instant::now();

        for _ in 0..runs {
            let _ = Lm::fit(&x_data, &y_data, n_obs, n_vars).unwrap();
        }

        let elapsed = start.elapsed();
        let avg_time_us = elapsed.as_micros() as f64 / runs as f64;
        let avg_time_ms = avg_time_us / 1000.0;

        println!(
            "  Average time: {:.2} μs ({:.3} ms)",
            avg_time_us, avg_time_ms
        );
        println!("  Throughput: {:.0} fits/second", 1_000_000.0 / avg_time_us);
    }

    println!("\n=== CLAUDE.MD TARGETS ===");
    println!("Target: ≥2x faster than R's lm()");
    println!("Current Rust performance measured above");
    println!("Next: Need direct R comparison to validate 2x speed claim");
}
